            for (auto [x, y] : teleport_list[i][j]) {
                long long new_t = t + 1;
                if (cost < dist[x][y][new_t]) {
                    dist[x][y][new_t] = cost;
                    pq.push({cost, x, y, new_t});
                }
            }
        }
    }

